    for doc in docs:
        text = doc['text']
        if proj in text:
            # Find all occurrences
            try:
                # Find indices
                indices = [m.start() for m in re.finditer(re.escape(proj), text)]

                for idx in indices:
                    snippet = text[idx:idx+2000] # Look ahead 2000 chars

                    # Split into lines
                    lines = snippet.split('\n')

                    # Check topics in the first few lines of the snippet?
                    # Or check the whole snippet.
                    if not is_disaster:
                        for kw in disaster_keywords:
                            if kw.lower() in snippet.lower():
                                is_disaster = True
                                break

                    # Check Start Date in lines
                    for line in lines:
                        line_lower = line.lower()
                        for phrase in start_phrases:
                            if phrase in line_lower:
                                if "2022" in line:
                                    started_2022 = True
                                    break
                        if started_2022:
                            break

                    if is_disaster and started_2022:
                        break
            except Exception:
                pass
        if is_disaster and started_2022:
            break

    if is_disaster and started_2022:
        matches[proj] = funding_map[proj]

total_amount = sum(matches.values())
print("__RESULT__:")
print(json.dumps({"total_funding": total_amount, "projects": list(matches.keys())}))
